// 提取文档中所有图编号并分析格式
var doc = Application.ActiveDocument;
var figNumbers = [];
var paragraphs = doc.Paragraphs;

for (var i = 0; i < paragraphs.Count; i++) {
    var text = paragraphs.Item(i).Range.Text;
    // 匹配常见图编号格式：图1、图 1-1、Figure 1、Fig. 1 等
    var patterns = [
        /图\s*(\d+)(?:[-–](\d+))?/g,
        /Figure\s*(\d+)(?:[-–](\d+))?/gi,
        /Fig\.?\s*(\d+)(?:[-–](\d+))?/gi
    ];

    for (var p = 0; p < patterns.length; p++) {
        var match;
        while ((match = patterns[p].exec(text)) !== null) {
            figNumbers.push({
                index: i,
                original: match[0],
                chapter: match[1] || '',
                figure: match[2] || ''
            });
        }
    }
}

return {
    total: figNumbers.length,
    figures: figNumbers
};

// 提取文档中所有图编号并分析格式（修正空段落处理）
var doc = Application.ActiveDocument;
var figNumbers = [];
var paragraphs = doc.Paragraphs;

for (var i = 0; i < paragraphs.Count; i++) {
    var para = paragraphs.Item(i);
    if (!para || !para.Range) continue;

    var text = para.Range.Text;
    // 匹配常见图编号格式：图1、图 1-1、Figure 1、Fig. 1 等
    var patterns = [
        /图\s*(\d+)(?:[-–](\d+))?/g,
        /Figure\s*(\d+)(?:[-–](\d+))?/gi,
        /Fig\.?\s*(\d+)(?:[-–](\d+))?/gi
    ];

    for (var p = 0; p < patterns.length; p++) {
        var match;
        while ((match = patterns[p].exec(text)) !== null) {
            figNumbers.push({
                index: i + 1,
                original: match[0],
                chapter: match[1] || '',
                figure: match[2] || ''
            });
        }
    }
}

return {
    total: figNumbers.length,
    figures: figNumbers
};

// 更全面地搜索所有可能的图编号格式
var doc = Application.ActiveDocument;
var figNumbers = [];
var paragraphs = doc.Paragraphs;

for (var i = 0; i < paragraphs.Count; i++) {
    var para = paragraphs.Item(i);
    if (!para || !para.Range) continue;

    var text = para.Range.Text;
    // 更广泛的匹配模式
    var patterns = [
        /图\s*\d+(?:[.\-–]\d+)?/g,
        /Figure\s*\d+(?:[.\-–]\d+)?/gi,
        /Fig\.?\s*\d+(?:[.\-–]\d+)?/gi,
        /插图\s*\d+/g,
        /图片\s*\d+/g
    ];

    for (var p = 0; p < patterns.length; p++) {
        var match;
        while ((match = patterns[p].exec(text)) !== null) {
            figNumbers.push({
                index: i + 1,
                original: match[0],
                text: text.substring(0, 50)
            });
        }
    }
}

return {
    total: figNumbers.length,
    figures: figNumbers
};
